const payload = $json.body ?? $json;

function parseCsvLine(line, delimiter) {
  const result = [];
  let current = '';
  let inQuotes = false;

  for (let i = 0; i < line.length; i++) {
    const char = line[i];
    if (char === '"') {
      if (inQuotes && line[i + 1] === '"') {
        current += '"';
        i += 1;
      } else {
        inQuotes = !inQuotes;
      }
      continue;
    }

    if (char === delimiter && !inQuotes) {
      result.push(current);
      current = '';
      continue;
    }

    current += char;
  }

  result.push(current);
  return result.map((cell) => String(cell || '').trim());
}

function parseCsvToRows(csvText) {
  const text = String(csvText || '').replace(/\r/g, '').trim();
  if (!text) return [];

  const lines = text.split('\n').filter((line) => line.trim() !== '');
  if (!lines.length) return [];

  const delimiter = lines[0].includes(';') ? ';' : ',';
  const headers = parseCsvLine(lines[0], delimiter);

  const rows = [];
  for (let i = 1; i < lines.length; i++) {
    const values = parseCsvLine(lines[i], delimiter);
    const row = {};
    headers.forEach((header, idx) => {
      row[header] = values[idx] ?? '';
    });
    rows.push(row);
  }

  return rows;
}

const required = ['origin_name', 'product_name', 'product_value', 'list_tag_name'];
const missing = required.filter((key) => payload[key] === undefined || payload[key] === null || String(payload[key]).trim() === '');
if (missing.length) {
  throw new Error(`Campos obrigatorios ausentes: ${missing.join(', ')}`);
}

const clintApiToken = payload.clint_api_token || payload.clintToken || process.env.CLINT_API_TOKEN || '';
if (!clintApiToken) {
  throw new Error('Token da Clint ausente. Envie clint_api_token no payload ou configure CLINT_API_TOKEN no ambiente do n8n.');
}

let rows = [];
if (Array.isArray(payload.rows)) {
  rows = payload.rows;
} else if (payload.csv_text) {
  rows = parseCsvToRows(payload.csv_text);
}

if (!Array.isArray(rows) || rows.length === 0) {
  throw new Error('Entrada invalida. Envie rows (array) ou csv_text (string CSV).');
}

return [{
  json: {
    execution_id: `${Date.now()}`,
    origin_name: String(payload.origin_name).trim(),
    product_name: String(payload.product_name).trim(),
    product_value: Number(payload.product_value || 0),
    list_tag_name: String(payload.list_tag_name).trim(),
    imported_at: new Date().toISOString(),
    clint_api_token: clintApiToken,
    clint_base_url: payload.clint_base_url || process.env.CLINT_BASE_URL || 'https://api.clint.digital/v1',
    rows
  }
}];

const input = $json;

const CONTACT_FIELDS_MAP = {
  'idade': 'idade',
  'profissao': 'profissao',
  'profissão': 'profissao',
  'qual sua profissão': 'profissao',
  'você é bacharel estudante ou advogado': 'profissao',
  'historico': 'historico',
  'histórico': 'historico',
  'foi aluno oab': 'foi_aluno_oab',
  'é ou já foi aluno vde oab': 'foi_aluno_oab',
  'e aluno concursos': 'e_aluno_concursos',
  'é aluno vde concursos carreiras jurídicas': 'e_aluno_concursos',
  'carreira pretendida': 'carreira_pretendida',
  'qual carreira jurídica pretende seguir': 'carreira_pretendida',
  'horas por dia': 'horas_por_dia',
  'quantas horas livres por dia você tem em média para estudar': 'horas_por_dia',
  'renda familiar': 'renda_familiar',
  'qual a sua renda familiar': 'renda_familiar',
  'features desejadas': 'features_desejadas',
  'o que você mais preza em um curso preparatório para o enam': 'features_desejadas',
  'maior dificuldade': 'maior_dificuldade',
  'qual a sua maior dificuldade na sua preparação para o enam': 'maior_dificuldade',
  'tempo de estudo': 'tempo_de_estudo',
  'há quanto tempo estuda pra concursos': 'tempo_de_estudo',
  'turma da oab': 'turma_da_oab',
  'turma da oab de interesse': 'turma_da_oab',
  'estuda para oab': 'estuda_para_oab',
  'disciplina segunda fase': 'disciplina_segunda_f',
  'produto de interesse': 'produto_de_interesse',
  'quantas horas por dia você estuda em média': 'quantas_horas_por_di',
  'quantas vezes você já fez a prova da oab': 'quantas_vezes_voce_j',
  'sentimento de aprovação atual': 'sentimento_de_aprova',
  'notas': 'notes',
  'notas do contato': 'notes'
};

const DEAL_FIELDS_MAP = {
  'utm source': 'utm_source',
  'utm medium': 'utm_medium',
  'utm campaign': 'utm_campaign',
  'utm term': 'utm_term',
  'utm content': 'utm_content',
  'produto': 'produto',
  'item combo': 'produto',
  'item': 'produto',
  'lista origem': 'lista_origem',
  'data importação': 'data_importacao',
  'data de importação': 'data_importacao'
};

function normalizeKey(key) {
  return String(key || '')
    .trim()
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/[?!:;,.()\[\]'\"]/g, '')
    .replace(/[-_/]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function normalizeValue(value) {
  if (value === undefined || value === null) return '';
  return String(value).trim();
}

function rowValueByAliases(row, aliases) {
  for (const [k, v] of Object.entries(row || {})) {
    const nk = normalizeKey(k);
    if (aliases.includes(nk)) {
      const nv = normalizeValue(v);
      if (nv) return nv;
    }
  }
  return '';
}

function digitsOnly(value) {
  return String(value || '').replace(/\D/g, '');
}

function buildPhonePayload(rawPhone) {
  const phoneClean = digitsOnly(rawPhone);
  if (!phoneClean) return { ddi: '', phone: '' };

  if (phoneClean.startsWith('55') && phoneClean.length > 11) {
    return { ddi: '+55', phone: phoneClean.slice(2) };
  }

  if (phoneClean.length >= 10) {
    return { ddi: '+55', phone: phoneClean };
  }

  return { ddi: '', phone: '' };
}

async function apiRequest(method, path, token, baseUrl, body = undefined) {
  const url = `${baseUrl.replace(/\/$/, '')}${path}`;
  const options = {
    method,
    headers: {
      'api-token': token,
      'Content-Type': 'application/json'
    }
  };

  if (body !== undefined) {
    options.body = JSON.stringify(body);
  }

  const response = await fetch(url, options);
  const text = await response.text();
  let data = {};
  try {
    data = text ? JSON.parse(text) : {};
  } catch (error) {
    data = { raw: text };
  }

  if (!response.ok) {
    throw new Error(`${method} ${path} -> ${response.status}: ${JSON.stringify(data).slice(0, 400)}`);
  }

  return data;
}

function extractId(payload) {
  return payload?.data?.id || payload?.id || null;
}

const rows = Array.isArray(input.rows) ? input.rows : [];
const token = input.clint_api_token;
const baseUrl = input.clint_base_url;

const originsResponse = await apiRequest('GET', '/origins?limit=250', token, baseUrl);
const origins = originsResponse?.data || [];

const wantedOrigin = String(input.origin_name || '').trim().toUpperCase();
const origin = origins.find((item) => String(item?.name || '').trim().toUpperCase() === wantedOrigin);
if (!origin) {
  throw new Error(`Origin '${input.origin_name}' nao encontrada.`);
}

const stages = Array.isArray(origin.stages) ? origin.stages : [];
const baseStage = stages.find((stage) => stage?.type === 'BASE') || stages[0];
if (!baseStage?.id) {
  throw new Error(`Origin '${input.origin_name}' sem stage valido.`);
}

let success = 0;
const failures = [];

for (let index = 0; index < rows.length; index++) {
  const row = rows[index] || {};
  const lineNumber = index + 2;

  try {
    const contactFields = {};
    const dealFields = {};

    const nameValue = rowValueByAliases(row, ['nome', 'name']);
    const emailValue = rowValueByAliases(row, ['email']);
    const phoneRaw = rowValueByAliases(row, ['telefone', 'phone', 'celular']);

    for (const [rawKey, rawValue] of Object.entries(row || {})) {
      const value = normalizeValue(rawValue);
      if (!value) continue;

      const rawNorm = String(rawKey || '').trim().toLowerCase();
      const key = normalizeKey(rawKey);

      if (['nome', 'name', 'email', 'telefone', 'phone', 'celular'].includes(key)) {
        continue;
      }

      if (CONTACT_FIELDS_MAP[key]) {
        contactFields[CONTACT_FIELDS_MAP[key]] = value;
        continue;
      }
      if (CONTACT_FIELDS_MAP[rawNorm]) {
        contactFields[CONTACT_FIELDS_MAP[rawNorm]] = value;
        continue;
      }
      if (DEAL_FIELDS_MAP[key]) {
        dealFields[DEAL_FIELDS_MAP[key]] = value;
        continue;
      }
      if (DEAL_FIELDS_MAP[rawNorm]) {
        dealFields[DEAL_FIELDS_MAP[rawNorm]] = value;
        continue;
      }
      if (Object.values(CONTACT_FIELDS_MAP).includes(rawNorm)) {
        contactFields[rawNorm] = value;
        continue;
      }
      if (Object.values(DEAL_FIELDS_MAP).includes(rawNorm)) {
        dealFields[rawNorm] = value;
      }
    }

    dealFields.lista_origem = input.origin_name;
    dealFields.data_importacao = input.imported_at;
    if (!dealFields.produto && input.product_name) {
      dealFields.produto = input.product_name;
    }

    if (!emailValue && !phoneRaw) {
      throw new Error('Linha sem e-mail ou telefone.');
    }

    const personName = nameValue || (emailValue ? emailValue.split('@')[0] : `lead-${lineNumber}`);
    const phoneParts = buildPhonePayload(phoneRaw);

    const contactPayload = {
      name: personName,
      email: emailValue,
      fields: contactFields
    };

    if (phoneParts.phone) {
      contactPayload.phone = phoneParts.phone;
      if (phoneParts.ddi) {
        contactPayload.ddi = phoneParts.ddi;
      }
    }

    let contactId = null;

    if (emailValue) {
      const emailSearch = await apiRequest(
        'GET',
        `/contacts?email=${encodeURIComponent(emailValue)}`,
        token,
        baseUrl
      );
      if ((emailSearch?.totalCount || 0) > 0 && Array.isArray(emailSearch?.data) && emailSearch.data[0]?.id) {
        contactId = emailSearch.data[0].id;
      }
    }

    if (!contactId && phoneParts.phone) {
      const phoneSearch = await apiRequest(
        'GET',
        `/contacts?phone=${encodeURIComponent(phoneParts.phone)}`,
        token,
        baseUrl
      );
      if ((phoneSearch?.totalCount || 0) > 0 && Array.isArray(phoneSearch?.data) && phoneSearch.data[0]?.id) {
        contactId = phoneSearch.data[0].id;
      }
    }

    if (contactId) {
      await apiRequest('POST', `/contacts/${contactId}`, token, baseUrl, contactPayload);
    } else {
      const createdContact = await apiRequest('POST', '/contacts', token, baseUrl, contactPayload);
      contactId = extractId(createdContact);
      if (!contactId) {
        throw new Error('Falha ao obter contact_id apos criacao.');
      }
    }

    if (input.list_tag_name) {
      await apiRequest('POST', `/contacts/${contactId}/tags`, token, baseUrl, [input.list_tag_name]);
    }

    const dealPayload = {
      contact_id: contactId,
      stage_id: baseStage.id,
      origin_id: origin.id,
      title: `${personName} - ${input.product_name}`,
      value: Number(input.product_value || 0),
      fields: Object.fromEntries(Object.entries(dealFields).filter(([, value]) => value !== null && value !== undefined && String(value).trim() !== ''))
    };

    await apiRequest('POST', '/deals', token, baseUrl, dealPayload);
    success += 1;
  } catch (error) {
    failures.push({
      linha: lineNumber,
      erro: error.message,
      email: rowValueByAliases(row, ['email']) || ''
    });
  }
}

return [{
  json: {
    status: failures.length ? 'partial_success' : 'success',
    message: 'Importacao executada no workflow Fase 1.',
    execution_id: input.execution_id,
    origin_name: input.origin_name,
    origin_id: origin.id,
    stage_id: baseStage.id,
    total_linhas: rows.length,
    sucessos: success,
    erros: failures.length,
    detalhes_falhas: failures
  }
}];
